30→    : inner_manager_(node), strip_large_messages_(strip_large_messages) {}
31→
32→void Ros2SubscriptionManager::set_message_callback(MessageCallback callback) {
33→  std::lock_guard<std::mutex> lock(callback_mutex_);
34→  callback_ = std::move(callback);
35→}
