37→bool Ros2SubscriptionManager::subscribe(const std::string& topic_name, const std::string& topic_type) {
38→  bool needs_stripping = strip_large_messages_ && MessageStripper::should_strip(topic_type);
39→
40→  Ros2MessageCallback ros2_callback =
41→      [this, topic_type, needs_stripping](
42→          const std::string& topic, const std::shared_ptr<rclcpp::SerializedMessage>& msg, uint64_t receive_time_ns) {
43→        const rclcpp::SerializedMessage* msg_to_use = msg.get();
44→        std::optional<rclcpp::SerializedMessage> stripped_msg;
45→
46→        if (needs_stripping) {
47→          try {
48→            stripped_msg.emplace(MessageStripper::strip(topic_type, *msg));
49→            msg_to_use = &*stripped_msg;
50→          } catch (const std::exception& e) {
51→            spdlog::warn("Failed to strip message on topic '{}': {}. Forwarding original.", topic, e.what());
52→          }
53→        }
54→
55→        const auto& rcl_msg = msg_to_use->get_rcl_serialized_message();
56→        auto data = std::make_shared<std::vector<std::byte>>(rcl_msg.buffer_length);
57→        std::memcpy(data->data(), rcl_msg.buffer, rcl_msg.buffer_length);
58→
59→        MessageCallback cb;
60→        {
61→          std::lock_guard<std::mutex> lock(callback_mutex_);
62→          cb = callback_;
63→        }
64→        if (cb) {
65→          cb(topic, std::move(data), receive_time_ns);
66→        }
67→      };
68→
69→  return inner_manager_.subscribe(topic_name, topic_type, ros2_callback);
70→}
71→
72→bool Ros2SubscriptionManager::unsubscribe(const std::string& topic_name) {
73→  return inner_manager_.unsubscribe(topic_name);
74→}
75→
76→void Ros2SubscriptionManager::unsubscribe_all() {
77→  inner_manager_.unsubscribe_all();
78→}
