 84→size_t GenericSubscriptionManager::get_reference_count(const std::string& topic_name) const {
 85→  std::lock_guard<std::mutex> lock(mutex_);
 86→
 87→  auto it = subscriptions_.find(topic_name);
 88→  if (it != subscriptions_.end()) {
 89→    return it->second.reference_count;
 90→  }
 91→
 92→  return 0;
